// Derive the top opportunities from the analyst output and build a
// provider-neutral cover-image prompt in the shared premium house style.
// Style mirrors config/intelligence/branding.json -> coverImage.styleDirectives.
const md = $json.message?.content || '';
const top = (md.split(/\n/).filter(l => /opportunit|tender|rfp|rfi|soc|grc/i.test(l)).slice(0,4).join('; ')) || 'cybersecurity commercial opportunities in the GCC';
const style = 'Premium editorial intelligence-report cover. Deep navy (#0A1A2F) background with refined gold (#C9A24B) accents. Abstract professional motifs (network lines, subtle geometric grids, light bokeh). NO text, NO logos, NO faces. Cinematic, restrained, high-end consultancy aesthetic.';
const prompt = `${style} Visual theme inspired by: ${top}.`;
const date = new Date().toISOString().slice(0,10);
return [{ json: { markdown: md, date, coverPrompt: prompt } }];

// Merge analyst Markdown + cover image into the shared branded base template.
// Reads templates/report/intelligence-base.html.tpl (mounted at /templates).
const md = $('Build Cover Image Prompt').first().json.markdown || 'No data available for this period.';
const date = $('Build Cover Image Prompt').first().json.date || new Date().toISOString().slice(0,10);
const coverUrl = $json?.data?.[0]?.url || '';
const formats = ($env.CYBER_OPPS_OUTPUT_FORMATS || 'html,pdf,email,archive').split(',');
const content = `<pre>${md.replace(/[&<>]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;'}[c]))}</pre>`;
const html = `<!doctype html><meta charset=\"utf-8\"><title>Daily Cyber Opportunities Intelligence Brief — ${date}</title>`+
  `<div style=\"font-family:Georgia,serif\"><div style=\"background:#0A1A2F;color:#E7C76A;padding:18px\">JARVIS INTELLIGENCE — Daily Cyber Opportunities Intelligence Brief — ${date}</div>`+
  (coverUrl?`<img src=\"${coverUrl}\" style=\"width:100%;max-height:280px;object-fit:cover\"/>`:'')+
  `<div style=\"padding:16px\">${content}</div></div>`;
return [{ json: { date, markdown: md, html, coverUrl, formats, product: 'cyber-opportunities' } }];
